 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import { Route, RouteComponentProps, Switch, useHistory } from 'react-router-dom';
 4	
 5	import '../_monitoring.scss';
 6	import {
 7	  getAlertRulesUrl,
 8	  getAlertsUrl,
 9	  getSilencesUrl,
10	  usePerspective,
11	} from '../hooks/usePerspective';
12	import AlertsPage from '../alerting/AlertsPage';
13	import SilencesPage from '../alerting/SilencesPage';
14	import AlertRulesPage from '../alerting/AlertRulesPage';
15	import {
16	  Divider,
17	  PageSection,
18	  PageSectionVariants,
19	  Tab,
20	  Tabs,
21	  TabTitleText,
22	  Title,
23	} from '@patternfly/react-core';
24	
25	const AlertingPage: React.FC<RouteComponentProps<{ url: string }>> = ({ match }) => {
26	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
27	  const { perspective } = usePerspective();
28	  const history = useHistory();
29	
30	  const alertsPath = getAlertsUrl(perspective);
31	  const silencesPath = getSilencesUrl(perspective);
32	  const rulesPath = getAlertRulesUrl(perspective);
33	  const paths = [alertsPath, silencesPath, rulesPath];
34	
35	  const { url } = match;
36	  let activeTabKey = -1;
37	  switch (url) {
38	    case alertsPath:
39	      activeTabKey = 0;
40	      break;
41	    case silencesPath:
42	      activeTabKey = 1;
43	      break;
44	    case rulesPath:
45	      activeTabKey = 2;
46	  }
47	
48	  const handleTabClick = (
49	    event: React.MouseEvent<any> | React.KeyboardEvent | MouseEvent,
50	    tabIndex: number | string,
51	  ) => {
52	    // prevent the href from redirecting as it causes a full page reload
53	    event.preventDefault();
54	    const tabNumber = Number(tabIndex);
55	    if (tabNumber > -1 && tabNumber < paths.length) {
56	      history.push(paths[tabNumber]);
57	      return;
58	    }
59	  };
60	
61	  return (
62	    <>
63	      <PageSection variant={PageSectionVariants.light}>
64	        <Title headingLevel="h1">{t('Alerting')}</Title>
65	      </PageSection>
66	      <Divider />
67	      {/* Without Page Section, the tabs get eaten by the components being switched to */}
68	      <PageSection variant={PageSectionVariants.light} padding={{ default: 'noPadding' }}>
69	        <Tabs activeKey={activeTabKey} onSelect={handleTabClick}>
70	          {/* Add href to tab so that when hovering you see the link in the bottom left */}
71	          <Tab eventKey={0} href={alertsPath} title={<TabTitleText>{t('Alerts')}</TabTitleText>} />
72	          <Tab
73	            eventKey={1}
74	            href={silencesPath}
75	            title={<TabTitleText>{t('Silences')}</TabTitleText>}
76	          />
77	          <Tab
78	            eventKey={2}
79	            href={rulesPath}
80	            title={<TabTitleText>{t('Alerting rules')}</TabTitleText>}
81	          />
82	        </Tabs>
83	      </PageSection>
84	      <Switch>
85	        <Route path={alertsPath} exact component={AlertsPage} />
86	        <Route path={silencesPath} exact component={SilencesPage} />
87	        <Route path={rulesPath} exact component={AlertRulesPage} />
88	      </Switch>
89	    </>
90	  );
91	};
92	
93	export default AlertingPage;

